# Prepare results container and search logic
def parse_product_json(text):
    try:
        import json
        return json.loads(text)
    except Exception:
        return None

def matches_criteria(prod, props):
    """
    Given a product record, return True if all specified user criteria match.
    props: dict of user criteria for product-properties (flattened if needed).
    """
    # product core fields
    if prod.get('brand', '').lower() != 'keter':
        return False
    # Series or model match for 'Deep Stack 2OO-VJU'
    matcher = lambda v: v.strip().lower() == 'deep stack 2oo-vju'
    if not (matcher(prod.get('series', '')) or matcher(prod.get('model', '')) or matcher(prod.get('name',''))):
        return False
    # Name/Description must suggest Storage Bin and Organizer (substring match)
    if not (('storage bin' in prod.get('name','').lower() and 'organizer' in prod.get('name','').lower()) or ('storage bin' in prod.get('description','').lower() and 'organizer' in prod.get('description','').lower())):
        return False
    # Storage type: parts case (the schema may put this in properties or somewhere else)
    propsdict = json.loads(prod.get('properties','{}')) if isinstance(prod.get('properties'), str) else prod.get('properties', {})
    if (propsdict.get('storage type','').lower() != 'parts case'):
        return False
    # Color family: yellow
    if (propsdict.get('color family','').lower() != 'yellow'):
        return False
    # Volume: 8 l, flexible matching (could be string or number; accept '8', '8l', '8 l')
    vol = str(propsdict.get('volume','')).replace(' ','').lower()
    if not (vol == '8l' or vol == '8' or vol == '8liter' or vol == '8liters'):
        return False
    # Must be wifi-enabled (see property or description)
    if not (propsdict.get('wifi-enabled','').lower() in ['true','yes','1'] or 'wifi' in prod.get('description','').lower()):
        return False
    return True

matching_products = []
for path, content in cat_contents.items():
    prod = parse_product_json(content) if content else None
    if not prod:
        continue
    if matches_criteria(prod, {}):
        matching_products.append({
            'sku': prod.get('sku'),
            'path': path,
            'name': prod.get('name'),
            'series': prod.get('series'),
            'model': prod.get('model'),
            'brand': prod.get('brand')
        })

# Step 2: Decision and answer
answer = '<NO>'
if matching_products:
    answer = '<YES>'
    # According to policy, reference the full path to the available product(s)
    answer = '\n'.join([f"<YES> {item['path']}" for item in matching_products])

# Record gates (search coverage & all checked)
scratchpad['search_coverage_gate'] = 'YES'
scratchpad['answer'] = answer
scratchpad['outcome'] = 'OUTCOME_OK'
# Add catalog file(s) to refs if not already present
for item in matching_products:
    if item['path'] not in refs:
        refs.append(item['path'])
scratchpad['refs'] = list(dict.fromkeys(refs))

def verify(sp):
    # All coverage: search_coverage_gate must be YES
    gate_nos = [k for k in sp if sp[k] in ('NO', 'BLOCKED')]
    if gate_nos:
        return False
    if sp.get('search_coverage_gate') != 'YES':
        return False
    # Answer must reflect call-1 data
    a = sp.get('answer', '')
    if a and not any(token in a for token in ['<YES>','<NO>']):
        return False
    if sp.get('outcome') != 'OUTCOME_OK':
        return False
    # All referenced files should be in refs
    for p in sp.get('refs', []):
        if not p.startswith('/'):
            return False
    return True

ws.answer(scratchpad, verify)
