import json
import re

def parse_fields(text):
    # Very simple parser for key: value pairs in the catalog content
    fields = {}
    lines = text.splitlines()
    for ln in lines:
        m = re.match(r'^(.*?):\s*(.*)$', ln.strip())
        if m:
            fields[m.group(1).strip().lower()] = m.group(2).strip().lower()
    return fields

# Key: (brand, line, typ, prop, val)
candidates = scratchpad['catalog_candidates']
read_catalog = {}
for path in scratchpad['refs']:
    if "/proc/catalog/" in path:
        name = path.split("/proc/catalog/")[-1]
        read_catalog[name] = ws.read(path)['content']

store_data = scratchpad.get('store_data', {})
store_json = json.loads(store_data['content']) if isinstance(store_data, dict) and 'content' in store_data else {}

# We have no direct pointer to inventory per-branch: occupation/inventory level presumably in catalog product json
