                items = json.loads(cf['content']) if isinstance(cf['content'], str) else cf['content']
                if isinstance(items, dict):  # in case it's a dict of SKUs
                    items = list(items.values())
                for prod in items:
                    # Now check for Husqvarna Compact 435 2ID-D4H Trimmer and Blower from Husqvarna, type grass trimmer, power source battery
                    name = (prod.get('name') or '').lower()
                    brand = (prod.get('brand') or '').lower()
                    line = (prod.get('line') or '').lower()
                    tool_type = (prod.get('tool_type') or '').lower()
                    power_src = (prod.get('power_source') or '').lower()
                    if (
                        'husqvarna' in brand and
                        'compact 435' in line and
                        (('trimmer' in name or 'blower' in name) or ('trimmer' in tool_type)) and
                        tool_type == 'grass trimmer' and
                        power_src == 'battery' and
                        name.startswith('husqvarna compact 435 2id-d4h')
                    ):
                        candidate_product_ids.append(prod['id'])
            except Exception:
                continue

# If catalog_files were empty, we need to scan with SQL
def get_available_stock(store_ids:List[str], product_ids:List[str])->int:
    if not store_ids or not product_ids:
        return 0
    # Compose SQL
    store_id_clause = ','.join([f'"{s}"' for s in store_ids])
    prod_id_clause = ','.join([f'"{s}"' for s in product_ids])
    sql = f"""
    SELECT SUM(stock) as total
    FROM inventory
    WHERE store_id IN ({store_id_clause})
    AND product_id IN ({prod_id_clause})
    """
    res = ws.exec('/bin/sql', stdin=sql.strip())
    try:
        lines = res['stdout'].splitlines()
        if len(lines) >= 2:
            stock_val = lines[1].strip()
            return int(stock_val) if stock_val else 0
        return 0
    except Exception:
        return 0

