scratchpad['answer'] = str(total_available)
scratchpad['outcome'] = 'OUTCOME_OK'
scratchpad['gates'] = {
    'search_coverage_gate': 'YES',
    'trust_gate': 'YES',
    'rule_conflict_gate': 'YES',
}
